// Validate and parse the input from the calling workflow
const input = $input.first().json;

if (!input.mode || !Array.isArray(input.items)) {
  throw new Error('LLM Classifier: Input must have { mode, items[] }');
}

const mode = input.mode;
const items = input.items;

// Build mode-specific system prompts
const systemPrompts = {
  feedback: `You are a product intelligence analyst. Classify each customer feedback item.

For each item, respond with a JSON object:
{
  "id": "<same id as input>",
  "problem_category": "<billing|onboarding|performance|feature-request|bug|support|compliment|other>",
  "sentiment": "<positive|negative|neutral|mixed>",
  "urgency": "<critical|high|medium|low>",
  "customer_segment": "<enterprise|growth|startup|consumer|unknown>",
  "product_area": "<from the list: onboarding,billing,core-product,integrations,performance,support,other>",
  "is_feature_request": <true|false>,
  "is_bug_report": <true|false>,
  "key_quote": "<the most impactful 1-2 sentences from the text>",
  "confidence": <0.0-1.0>,
  "reasoning": "<1-2 sentences explaining your classification>"
}

Respond ONLY with a JSON array of these objects. No extra text.`,

  competitor: `You are a competitive intelligence analyst. Analyze the following change detected on a competitor's website.

For each item, respond with a JSON object:
{
  "id": "<same id as input>",
  "change_type": "<pricing|feature|positioning|hiring|content|design|partnership|other>",
  "importance_score": <1-10>,
  "possible_reason": "<why did they make this change, in 1-2 sentences>",
  "product_impact": "<how this could affect your product strategy, in 1-2 sentences>",
  "recommended_response": "<what your team should consider doing, in 1-2 sentences>",
  "confidence": <0.0-1.0>,
  "reasoning": "<1-2 sentences explaining your analysis>"
}

Respond ONLY with a JSON array of these objects. No extra text.`,

  brief: `You are a product manager writing a concise executive brief.

For each item (a data point from the week), respond with a JSON object:
{
  "id": "<same id as input>",
  "category": "<shipped|metric|insight|blocker|risk|decision|priority>",
  "priority": <1-10>,
  "summary": "<one sentence summary>",
  "impact": "<business impact, 1 sentence>",
  "action_required": <true|false>,
  "confidence": <0.0-1.0>,
  "reasoning": "<1-2 sentences>"
}

Respond ONLY with a JSON array of these objects. No extra text.`
};

const systemPrompt = systemPrompts[mode];
if (!systemPrompt) {
  throw new Error(`LLM Classifier: Unknown mode '${mode}'. Use feedback, competitor, or brief.`);
}

// Format items for the user message
const userMessage = JSON.stringify(
  items.map(item => ({ id: item.id, text: item.text, metadata: item.metadata || {} })),
  null,
  2
);

return [{
  json: {
    mode,
    items,
    systemPrompt,
    userMessage,
    model: mode === 'feedback' || mode === 'brief'
      ? (process.env.AI_MODEL_FAST || 'gpt-4o-mini')
      : (process.env.AI_MODEL_SMART || 'gpt-4o'),
    itemCount: items.length,
  }
}];

// Parse the AI response and validate it
const aiResponse = $input.first().json;
const originalData = $('Build Classification Prompt').first().json;

let rawContent;
try {
  // The response format depends on the model and n8n version
  rawContent = aiResponse?.message?.content ||
               aiResponse?.choices?.[0]?.message?.content ||
               aiResponse?.content ||
               JSON.stringify(aiResponse);
} catch (e) {
  throw new Error('LLM Classifier: Could not extract content from AI response');
}

let classifications;
try {
  const parsed = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
  // The AI may return an array directly or wrapped in a key
  classifications = Array.isArray(parsed) ? parsed : (parsed.results || parsed.items || [parsed]);
} catch (e) {
  throw new Error(`LLM Classifier: Failed to parse AI JSON response: ${e.message}\nRaw: ${String(rawContent).substring(0, 200)}`);
}

// Map results back to original items by ID
const resultMap = new Map(classifications.map(c => [c.id, c]));

const results = originalData.items.map(item => {
  const classification = resultMap.get(item.id);
  if (!classification) {
    return {
      id: item.id,
      classification: null,
      confidence: 0,
      reasoning: 'No classification returned by AI',
      error: true,
    };
  }
  return {
    id: item.id,
    classification,
    confidence: parseFloat(classification.confidence) || 0,
    reasoning: classification.reasoning || '',
    error: false,
  };
});

return [{
  json: {
    mode: originalData.mode,
    results,
    total: results.length,
    classified: results.filter(r => !r.error).length,
    failed: results.filter(r => r.error).length,
  }
}];

// Error handler — log the error and return a safe fallback
const error = $input.first().json;
const errorMessage = error?.message || String(error) || 'Unknown error';

console.error(`LLM Classifier error: ${errorMessage}`);

// Return a safe empty result so calling workflows can handle the failure gracefully
return [{
  json: {
    mode: 'unknown',
    results: [],
    total: 0,
    classified: 0,
    failed: 0,
    error: true,
    errorMessage,
  }
}];
